private void addApname(JSONObject resultObject, String apname, RagicBundle bundle, User user, boolean apOnly, boolean additionalInfo) throws JSONException {

    JSONObject apnameObject=new JSONObject();
    resultObject.put(apname, apnameObject);
    Account acc = Account.getInstance(apname);
    AccountSetting accSetting = acc.getAppSetting();
    String companyName = accSetting.getCompanyName();
    apnameObject.put("label", companyName);
    if(apOnly) return;
    apnameObject.put("name",apname);

    if("TKSFULLHOUSE".equals(apname)) {
        new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("Start");
    }

    String redirectServer = RemoteAccountManager.main_getServer(apname);
    AccountTranslation trans = Account.getInstance(apname).getAccountTranslation();
    Optional<String> transKey = trans.bundleToKey(bundle);
    if(redirectServer!=null && License.isProd()){

        if("TKSFULLHOUSE".equals(apname)) {
            new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("Up");
        }

      apnameObject.put("server",redirectServer);
      JSONObject apnameChildren= URLCaller.get("https://"+redirectServer+"/api/internal/local_accountInfo.jsp?a="+apname+"&e="+ Encoder.encodeURIComponent(user.getUserId()) + (transKey.isPresent()? "&trans=" + transKey.get(): "") + (additionalInfo ? "&additionalInfo" :"") + (bundle != null ? "&lang=" + bundle.getLocale().getLanguage() + "-" + bundle.getLocale().getCountry() : "&lang=en-US"));
      apnameObject.put("children",apnameChildren);

      if(apnameChildren != null && apnameChildren.optJSONObject("reportTab") != null) {
        apnameObject.put("reportTab", apnameChildren.optJSONObject("reportTab"));
        apnameChildren.remove("reportTab");
      }

      if(apnameChildren != null && apnameChildren.optJSONArray("groups") != null) {
        apnameObject.put("groups", apnameChildren.optJSONArray("groups"));
        apnameChildren.remove("groups");
      }

      if(apnameChildren != null && apnameChildren.optString("access authority") != null) {
        apnameObject.put("access authority", apnameChildren.optBoolean("access authority"));
        apnameChildren.remove("access authority");
      }

      if(apnameChildren != null && apnameChildren.optJSONObject("additionalInfo") != null) {
          JSONObject additionalInfoJo = apnameChildren.optJSONObject("additionalInfo");
          apnameObject.put("ragicId", additionalInfoJo.optInt("ragicId"));
          apnameObject.put("username", additionalInfoJo.optString("username"));
          apnameObject.put("external", additionalInfoJo.optBoolean("external"));
          if(additionalInfoJo.has("needChangePassword"))
          apnameObject.put("needChangePassword", additionalInfoJo.optString("needChangePassword"));
          apnameChildren.remove("additionalInfo");
      }
    }
    else{
      if(License.isProd()) apnameObject.put("server","www.ragic.com");
      else apnameObject.put("server",RagicConfig.getInstance().getProperty("SERVER_NAME"));


        if("TKSFULLHOUSE".equals(apname)) {
            new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("Down");
        }

      int accessFormCount = 0;
      JSONObject apnameChildren=new JSONObject();
      apnameObject.put("children",apnameChildren);

      List<MenuSet> mslist=Account.getInstance(apname).getMenuConfiguration().getMenuSets();
      int tabSeq=1;
      int menusetIndex=0;
      for(MenuSet ms:mslist){
        if(ms==null) {
            if("TKSFULLHOUSE".equals(apname)) {
                new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("ms is null");
            }
            continue;
        }
        for(MenuTab tab:ms.listTabs(user,Const.USER,true,false)){
          if(tab==null) {
              if("TKSFULLHOUSE".equals(apname)) {
                  new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("tab is null");
              }
              continue;
          }

          if(tab.getName().equals("Report")) {
              List<MenuItem> items = tab.getItems();
              items.forEach(i -> {
                  try {
                      System.out.println(i.getJSON().toString(2));
                  } catch (Exception ignored) {

                  }
                  });
          }

          if(!tab.isRagicSetup()) {
            accessFormCount++;
          };

//          if(tab.isReportTab()) {
////              if("TKSFULLHOUSE".equals(apname)) {
////                  new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("isReportTab");
////              }
//              JSONObject reportTabJO=new JSONObject();
//              apnameObject.put("reportTab",reportTabJO);
//              reportTabJO.put("seq", tabSeq++);
//              ReportConfig rc=Account.getInstance(apname).getReportConfig();
//              int index=0;
//              for(Report r:rc.listReports(user)){
//                  JSONObject reportJSON=new JSONObject();
//                  reportJSON.put("name",r.getName());
//                  reportJSON.put("seq",++index);
//                  reportJSON.put("reportId",r.getId());
//                  reportTabJO.put(""+index,reportJSON);
//              }
//          } else {

              if("TKSFULLHOUSE".equals(apname)) {
                  new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("is not report tab");
              }
              JSONObject insObject=new JSONObject();
              JSONObject insChildren=new JSONObject();
              apnameChildren.put(tab.getPath(),insObject);

              String applicationName = tab.getName(bundle);

              insObject.put("name",Encoder.htmlUnescape(applicationName));
              insObject.put("seq",tabSeq++);
              insObject.put("children",insChildren);

              insObject.put("menuset",ms.getName(bundle));
              insObject.put("menusetIndex",menusetIndex);

              MenuConfiguration mc = Account.getInstance(apname).getMenuConfiguration();
              MenuTab menuTab = mc.getMenuTab(tab.getPath());

              if(menuTab != null) {
                  int count = 0;
                  List<MenuItem> items = menuTab.getItems();
                  synchronized (items){
                      for(MenuItem item : items) {
                          JSONObject itemJson = item.getJSON();
                          String type = itemJson.optString("type");

                          if(item instanceof MenuSheet) {
                              int rightsLevel = user.getRightsLevel(item.getApname(), ((MenuSheet)item).getPath(), item.getRights());
                              if(rightsLevel < Const.USER) {
                                  if("TKSFULLHOUSE".equals(apname)) {
                                      new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info("no rights, type: " + type + ", " + item.getApname() +  ((MenuSheet)item).getPath() + "/" + item.getRights());
                                  }
                                  continue;
                              }
                          }

                          switch (type) {
                              case "sheet":
                                  JSONObject formObject=new JSONObject();
                                  insChildren.put("" + itemJson.optInt("si"),formObject);
                                  formObject.put("name",item.getName(bundle));
                                  formObject.put("type", type);
                                  formObject.put("seq",count);

                                  if("TKSFULLHOUSE".equals(apname)) {
                                      new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info(formObject.toString(2));
                                  }
                                  break;
                              case "url":
                                  JSONObject urlObject=new JSONObject();
                                  insChildren.put("" + (count + 1) * -1, urlObject);
                                  urlObject.put("name",item.getName(bundle));
                                  urlObject.put("type", type);
                                  urlObject.put("id", itemJson.optInt("id"));

                                  String url=itemJson.optString("url");
                                  urlObject.put("url", url);
                                  //[BugId:15432]
                                  if(url!=null && url.contains("/action/")){
                                      String[] sections=url.split("/");
                                      NUIForm form=AppManager.getFormPage(apname,"/"+sections[2],Encoder.parseInt(sections[3]));
                                      if(form!=null){
                                          ActionButton button=form.getActionButton(sections[5]);
                                          if(button!=null){
                                              urlObject.put("actionButtonName",button.getName());
                                              urlObject.put("type", "action");
                                          }
                                      }
                                  }
                                  urlObject.put("seq",count);

                                  if("TKSFULLHOUSE".equals(apname)) {
                                      new Log("log/TKSFULLHOUSE.log").setIfDisplayTime(true).info(urlObject.toString(2));
                                  }
                                  break;
                              case "report":
                                  JSONObject reportObject=new JSONObject();
                                  insChildren.put("" + (count + 1) * -1, reportObject);
                                  reportObject.put("name",item.getName(bundle));
                                  reportObject.put("type", type);
                                  reportObject.put("reportId", itemJson.optInt("reportId", -1));
                                  reportObject.put("seq",count);
                                  break;
                          }

                          count++;
                      }
                  }
              }

              Map<String,String> forms=AppManager.getFormNamesInPath(apname,tab.getPath(),user, Const.USER);
              int count=1;
              for(Map.Entry<String,String> e:forms.entrySet()){
                  String formKey=e.getKey();
                  String[] formKeySplit=formKey.split("_");
                  String formIndex=formKeySplit[0];

                  String formName=e.getValue();
                  formName = trans.translate(formName, bundle.getLocale(), Encoder.parseInt(formIndex) >= Const.TEMPLATE_START_SHEET_INDEX, AccountTranslation.EncodingType.NO_ENCODING);

                  JSONObject formObject=new JSONObject();
                  insChildren.put(formIndex,formObject);
                  formObject.put("name",formName);
                  formObject.put("seq",count);
                  count++;
              }
//          }


        }
        menusetIndex++;
      }

        //[BugId:12248] Report tab
        JSONObject reportTabJO=new JSONObject();
        apnameObject.put("reportTab",reportTabJO);
        ReportConfig rc=Account.getInstance(apname).getReportConfig();
        int index=0;
        for(Report r:rc.listReports()){
            boolean access = r.access(user, Const.USER, apname);
            if(access) {
                JSONObject reportJSON=new JSONObject();
                reportJSON.put("name",r.getName());
                reportJSON.put("seq",++index);
                reportJSON.put("reportId",r.getId());
                reportTabJO.put(""+index,reportJSON);
            }
        }

      boolean realEmpty = AppManager.ifEmpty(apname);
      apnameObject.put("access authority", !(!realEmpty && accessFormCount == 0));
      if(additionalInfo) {
          int userNodeId = user.getUserNodeId(apname);
          if(userNodeId > -1) {
              apnameObject.put("ragicId", user.getUserNodeId(apname));
              apnameObject.put("username", user.getUserName(apname));
              apnameObject.put("external", user.getIfExternalv2(apname));
              AbstractMap.SimpleEntry<Boolean, User.PasswordChangeType> needChangePwd = Util.checkUserNeedChangePassword(user, apname);
              if(needChangePwd.getKey()) {
                apnameObject.put("needChangePassword", needChangePwd.getValue().getDescription(bundle));
              }
          }

          Collection<String> groups = new ArrayList<>();
          Set<String> userGroups=user.getGroups(apname);
          groups.addAll(userGroups);
          for(String g:userGroups) groups.add(g.toUpperCase());
          apnameObject.put("groups", groups);
      }
    }
  }
